{
  "options": [
    {
      "text": "坦诚说出你的观察：康纳在试探，罗英在等，这里的人都在观望。",
      "actionId": ""
    },
    {
      "text": "反问回去：你希望我看到了什么？",
      "actionId": ""
    },
    {
      "text": "跳过直接回答，问她在想什么。",
      "actionId": ""
    },
    {
      "text": "简短回应：一场精心设计的笼子。",
      "actionId": ""
    }
  ]
}
